// And groups predicates with the AND operator between them.
func And(predicates ...predicate.StorageNode) predicate.StorageNode {
	return predicate.StorageNode(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.StorageNode) predicate.StorageNode {
	return predicate.StorageNode(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.StorageNode) predicate.StorageNode {
	return predicate.StorageNode(sql.NotPredicates(p))
}
